import { Component, EventEmitter, Input, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { MatExpansionModule } from '@angular/material/expansion';
import { MatIconModule } from '@angular/material/icon';
import { MatButtonModule } from '@angular/material/button';
import { MatTooltipModule } from '@angular/material/tooltip';
import { MatDialog } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { Account } from '../../../core/models/account.model';
import { AccountService } from '../../../core/services/account.service';
import { TransactionListComponent } from '../transaction-list/transaction-list.component';
import { ConfirmDialogComponent } from '../../../shared/components/confirm-dialog/confirm-dialog.component';
import { TransactionDialogComponent } from '../transaction-dialog/transaction-dialog.component';

@Component({
  selector: 'app-account-card',
  standalone: true,
  imports: [
    CommonModule, MatExpansionModule, MatIconModule,
    MatButtonModule, MatTooltipModule, TransactionListComponent,
  ],
  templateUrl: './account-card.component.html',
})
export class AccountCardComponent {
  @Input() account!: Account;
  @Input() customerId!: number;
  @Output() accountDeleted = new EventEmitter<void>();
  @Output() balanceUpdated = new EventEmitter<void>();

  refreshTrigger = 0;

  constructor(
    private accountService: AccountService,
    private dialog: MatDialog,
    private snackBar: MatSnackBar,
  ) {}

  get isActive(): boolean {
    return this.account.status === 'ACTIVE';
  }

  get typeClass(): string {
    return this.account.accountType === 'SAVINGS' ? 'savings' : 'checking';
  }

  get typeLabel(): string {
    return this.account.accountType === 'SAVINGS' ? 'Ahorro' : 'Corriente';
  }

  get typeIcon(): string {
    return this.account.accountType === 'SAVINGS' ? 'savings' : 'account_balance_wallet';
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency', currency: 'COP', minimumFractionDigits: 2,
    }).format(value);
  }

  openTransactionDialog(event: MouseEvent): void {
    event.stopPropagation();
    const ref = this.dialog.open(TransactionDialogComponent, {
      data: { account: this.account },
      width: '480px',
    });
    ref.afterClosed().subscribe(success => {
      if (success) {
        this.refreshTrigger++;
        this.balanceUpdated.emit();
      }
    });
  }

  confirmDelete(event: MouseEvent): void {
    event.stopPropagation();
    const ref = this.dialog.open(ConfirmDialogComponent, {
      data: {
        title: 'Eliminar cuenta',
        message: `¿Eliminar la cuenta <strong>${this.account.accountNumber}</strong>?<br>
          Saldo actual: <strong>${this.formatCurrency(this.account.balance)}</strong>.<br>
          Esta acción no se puede deshacer.`,
        confirmLabel: 'Eliminar',
      },
      width: '400px',
    });
    ref.afterClosed().subscribe(confirmed => {
      if (!confirmed) return;
      this.accountService.delete(this.account.id).subscribe({
        next: () => {
          this.snackBar.open('Cuenta eliminada exitosamente', 'Cerrar', { duration: 3000 });
          this.accountDeleted.emit();
        },
        error: (err: Error) => {
          this.snackBar.open(err.message, 'Cerrar', { duration: 5000, panelClass: 'snack-error' });
        },
      });
    });
  }
}
<mat-expansion-panel class="account-panel" [class.inactive]="!isActive">
  <mat-expansion-panel-header>
    <div class="account-panel-header">
      <div class="account-icon" [class]="typeClass">
        <mat-icon>{{ typeIcon }}</mat-icon>
      </div>
      <div class="account-info">
        <div class="account-number">
          {{ account.accountNumber }}
          <span class="status-chip" [class]="isActive ? 'active' : 'inactive'">
            {{ isActive ? 'Activa' : 'Inactiva' }}
          </span>
        </div>
        <div class="account-type">Cuenta de {{ typeLabel }}</div>
      </div>
      <div class="account-balance">
        <div class="balance-label">Saldo disponible</div>
        <div class="balance-amount" [style.color]="account.balance < 0 ? '#ef4444' : '#1e293b'">
          {{ formatCurrency(account.balance) }}
        </div>
      </div>

      <!-- Botón: Nueva transacción -->
      <button mat-icon-button class="account-action-btn tx-btn"
              (click)="openTransactionDialog($event)"
              [disabled]="!isActive"
              [matTooltip]="isActive ? 'Nueva transacción' : 'Cuenta inactiva'">
        <mat-icon>add_circle_outline</mat-icon>
      </button>

      <!-- Botón: Eliminar -->
      <button mat-icon-button class="account-action-btn delete-btn"
              (click)="confirmDelete($event)"
              matTooltip="Eliminar cuenta">
        <mat-icon>delete</mat-icon>
      </button>
    </div>
  </mat-expansion-panel-header>

  <!-- Panel expandido: Últimas 5 transacciones -->
  <div class="account-panel-content">
    <div class="panel-section">
      <div class="section-label">
        <mat-icon>history</mat-icon>
        Últimas 5 transacciones
      </div>
      <app-transaction-list
        [accountId]="account.id"
        [refreshTrigger]="refreshTrigger">
      </app-transaction-list>
    </div>
  </div>
</mat-expansion-panel>
